        (fun v0 v1 v2 -> TrackNameNode.TrackName (v0, v1, v2))
do trackNameRefImpl.Value <- trackNameParser

let private instrumentNameParser : Parser<InstrumentNameNode, unit> =
    pipe3
        (pstring "0x04")
        (lengthRef)
        (textRef)
        (fun v0 v1 v2 -> InstrumentNameNode.InstrumentName (v0, v1, v2))
do instrumentNameRefImpl.Value <- instrumentNameParser

let private lyricParser : Parser<LyricNode, unit> =
    pipe3
        (pstring "0x05")
        (lengthRef)
        (textRef)
        (fun v0 v1 v2 -> LyricNode.Lyric (v0, v1, v2))
do lyricRefImpl.Value <- lyricParser

let private markerParser : Parser<MarkerNode, unit> =
    pipe3
        (pstring "0x06")
        (lengthRef)
        (textRef)
        (fun v0 v1 v2 -> MarkerNode.Marker (v0, v1, v2))
do markerRefImpl.Value <- markerParser

let private cuePointParser : Parser<CuePointNode, unit> =
    pipe3
        (pstring "0x07")
        (lengthRef)
        (textRef)
        (fun v0 v1 v2 -> CuePointNode.CuePoint (v0, v1, v2))
do cuePointRefImpl.Value <- cuePointParser

let private channelPrefixParser : Parser<ChannelPrefixNode, unit> =
    pipe3
        (pstring "0x20")
        (pstring "length 1")
        (channelRef)
        (fun v0 v1 v2 -> ChannelPrefixNode.ChannelPrefix (v0, v1, v2))
do channelPrefixRefImpl.Value <- channelPrefixParser

let private endOfTrackParser : Parser<EndOfTrackNode, unit> =
    pipe2
        (pstring "0x2F")
        (pstring "length 0")
        (fun v0 v1 -> EndOfTrackNode.EndOfTrack (v0, v1))
do endOfTrackRefImpl.Value <- endOfTrackParser

let private tempoParser : Parser<TempoNode, unit> =
    pipe3
        (pstring "0x51")
        (pstring "length 3")
        (microsecondsPerQuarterRef)
        (fun v0 v1 v2 -> TempoNode.Tempo (v0, v1, v2))
do tempoRefImpl.Value <- tempoParser

let private microsecondsPerQuarterParser : Parser<MicrosecondsPerQuarterNode, unit> =
    pipe3
        (byteRef)
        (byteRef)
        (byteRef)
        (fun v0 v1 v2 -> MicrosecondsPerQuarterNode.MicrosecondsPerQuarter (v0, v1, v2))
do microsecondsPerQuarterRefImpl.Value <- microsecondsPerQuarterParser

let private smpteOffsetParser : Parser<SmpteOffsetNode, unit> =
    pipe2
        (pstring "0x54")
        (
        pipe2
            (pstring "length 5")
            (
            pipe5
                (hourRef)
                (minuteRef)
                (secondRef)
                (frameRef)
                (fractionalFrameRef)
                (fun t0 t1 t2 t3 t4 -> (t0, t1, t2, t3, t4))            )
            (fun t0 (t1, t2, t3, t4, t5) -> (t0, t1, t2, t3, t4, t5))        )
        (fun v0 (v1, v2, v3, v4, v5, v6) -> SmpteOffsetNode.SmpteOffset (v0, v1, v2, v3, v4, v5, v6))
do smpteOffsetRefImpl.Value <- smpteOffsetParser

let private hourParser : Parser<HourNode, unit> =
    byteRef |>> HourNode.Hour

do hourRefImpl.Value <- hourParser

let private minuteParser : Parser<MinuteNode, unit> =
    byteRef |>> MinuteNode.Minute

do minuteRefImpl.Value <- minuteParser

let private secondParser : Parser<SecondNode, unit> =
    byteRef |>> SecondNode.Second

do secondRefImpl.Value <- secondParser

let private frameParser : Parser<FrameNode, unit> =
    byteRef |>> FrameNode.Frame

do frameRefImpl.Value <- frameParser

let private fractionalFrameParser : Parser<FractionalFrameNode, unit> =
    byteRef |>> FractionalFrameNode.FractionalFrame

do fractionalFrameRefImpl.Value <- fractionalFrameParser

let private timeSignatureParser : Parser<TimeSignatureNode, unit> =
    pipe2
        (pstring "0x58")
        (
        pipe5
            (pstring "length 4")
            (numeratorRef)
            (denominatorRef)
            (clocksRef)
            (thirtySecondsRef)
            (fun t0 t1 t2 t3 t4 -> (t0, t1, t2, t3, t4))        )
        (fun v0 (v1, v2, v3, v4, v5) -> TimeSignatureNode.TimeSignature (v0, v1, v2, v3, v4, v5))
do timeSignatureRefImpl.Value <- timeSignatureParser

let private numeratorParser : Parser<NumeratorNode, unit> =
    byteRef |>> NumeratorNode.Numerator

do numeratorRefImpl.Value <- numeratorParser

let private denominatorParser : Parser<DenominatorNode, unit> =
    pstring "byte (power of 2: 2^n)" |>> DenominatorNode.Denominator

do denominatorRefImpl.Value <- denominatorParser

let private clocksParser : Parser<ClocksNode, unit> =
    byteRef |>> ClocksNode.Clocks

do clocksRefImpl.Value <- clocksParser

let private thirtySecondsParser : Parser<ThirtySecondsNode, unit> =
    byteRef |>> ThirtySecondsNode.ThirtySeconds

do thirtySecondsRefImpl.Value <- thirtySecondsParser

let private keySignatureParser : Parser<KeySignatureNode, unit> =
    pipe4
        (pstring "0x59")
        (pstring "length 2")
        (sharpsFlatsRef)
        (majorMinorRef)
        (fun v0 v1 v2 v3 -> KeySignatureNode.KeySignature (v0, v1, v2, v3))
do keySignatureRefImpl.Value <- keySignatureParser

let private sharpsFlatsParser : Parser<SharpsFlatsNode, unit> =
    pstring "signed byte (-7 to +7)" |>> SharpsFlatsNode.SharpsFlats

do sharpsFlatsRefImpl.Value <- sharpsFlatsParser

let private majorMinorParser : Parser<MajorMinorNode, unit> =
    pstring "byte (0 = major, 1 = minor)" |>> MajorMinorNode.MajorMinor

do majorMinorRefImpl.Value <- majorMinorParser

let private sequencerSpecificParser : Parser<SequencerSpecificNode, unit> =
    pipe3
        (pstring "0x7F")
        (lengthRef)
        (dataRef)
        (fun v0 v1 v2 -> SequencerSpecificNode.SequencerSpecific (v0, v1, v2))
do sequencerSpecificRefImpl.Value <- sequencerSpecificParser

let private lengthParser : Parser<LengthNode, unit> =
    vlqRef |>> LengthNode.Length

do lengthRefImpl.Value <- lengthParser

let private textParser : Parser<TextNode, unit> =
    many (byteRef) |>> TextNode.Text

do textRefImpl.Value <- textParser

let private dataParser : Parser<DataNode, unit> =
    many (byteRef) |>> DataNode.Data

do dataRefImpl.Value <- dataParser

let private sysexEventParser : Parser<SysexEventNode, unit> =
    choice [
        attempt (sysexStartRef |>> SysexEventNode.SysexStart)
        attempt (sysexContinueRef |>> SysexEventNode.SysexContinue) ]

do sysexEventRefImpl.Value <- sysexEventParser

let private sysexStartParser : Parser<SysexStartNode, unit> =
    pipe4
        (pstring "0xF0")
        (lengthRef)
        (sysexDataRef)
        (pstring "0xF7")
        (fun v0 v1 v2 v3 -> SysexStartNode.SysexStart (v0, v1, v2, v3))
do sysexStartRefImpl.Value <- sysexStartParser

let private sysexContinueParser : Parser<SysexContinueNode, unit> =
    pipe3
        (pstring "0xF7")
        (lengthRef)
        (sysexDataRef)
        (fun v0 v1 v2 -> SysexContinueNode.SysexContinue (v0, v1, v2))
do sysexContinueRefImpl.Value <- sysexContinueParser

let private sysexDataParser : Parser<SysexDataNode, unit> =
    many (byteRef) |>> SysexDataNode.SysexData

do sysexDataRefImpl.Value <- sysexDataParser

/// Parse Midi from a string. Returns Ok or Error.
let parse (input: string) : Result<ByteNode, string> =
    match run (byteParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
